mapper.select:
SELECT ,
FROM yx_push_task t LEFT JOIN yx_user u ON t.sender_id = u.id AND u.is_deleted = FALSE WHERE t.is_deleted = FALSE
AND t.status = #{status}
ORDER BY t.created_at DESC LIMIT #{limit} OFFSET #{offset}

mapper.insert:
INSERT INTO yx_push_task (
    title, content, target_type, target_filter, status,
    sender_id, recipient_count, read_count
) VALUES (
    #{title}, #{content}, #{targetType}, #{targetFilter}, #{status},
    #{senderId}, #{recipientCount}, #{readCount}
)

mapper.update:
UPDATE yx_push_task
SET read_count = read_count + 1, updated_at = NOW()
WHERE id = #{id}
